// Sends a promoter invite link to a recipient via Resend.
//
// POST body: { email, name, invite_url, origin }
//   - email:      where to send
//   - name:       recipient's name (optional, falls back to "there")
//   - invite_url: the /join?invite=TOKEN link generated by PlatformAdmin
//   - origin:     site origin (for the footer link)
//
// Required env: RESEND_API_KEY

exports.handler = async (event) => {
  if (event.httpMethod !== 'POST') {
    return { statusCode: 405, body: JSON.stringify({ error: 'Method not allowed' }) }
  }

  try {
    const { email, name, invite_url, origin } = JSON.parse(event.body || '{}')
    if (!email || !invite_url) throw new Error('email and invite_url required')

    const greeting = name ? `Hi ${escapeHtml(name)},` : 'Hi there,'
    const site     = (origin || 'https://grail.mx').replace(/\/$/, '')

    const html = `
      <div style="font-family: -apple-system, system-ui, sans-serif; max-width: 480px; margin: 0 auto; padding: 32px 24px; background: #0e0e14; color: #e8e0d0; border-radius: 14px;">
        <div style="font-size: 11px; color: #dd22aa; text-transform: uppercase; letter-spacing: 0.15em; font-weight: 700; margin-bottom: 8px;">GRAIL · Promoter Invite</div>
        <h2 style="margin: 0 0 16px 0; color: #e8e0d0; font-size: 1.5rem; letter-spacing: -0.02em;">${greeting}</h2>
        <p style="margin: 0 0 16px 0; line-height: 1.55;">You're approved to set up a promoter account on GRAIL. Click the link below to claim your invite, sign up, and start your event.</p>
        <p style="margin: 24px 0;">
          <a href="${invite_url}" style="display: inline-block; background: linear-gradient(135deg, #c8922a, #e8b84b); color: #000; padding: 12px 24px; border-radius: 10px; font-weight: 800; text-decoration: none; letter-spacing: 0.02em;">Claim your invite →</a>
        </p>
        <p style="margin: 0 0 12px 0; color: #8a8098; font-size: 13px; line-height: 1.5;">Or paste this URL into your browser:</p>
        <p style="margin: 0 0 24px 0; word-break: break-all; color: #aaff00; font-size: 13px;">${invite_url}</p>
        <hr style="border: none; border-top: 1px solid #1e1e2a; margin: 24px 0;" />
        <p style="margin: 0; color: #8a8098; font-size: 12px;">This invite is single-use. If you didn't request this, ignore the email.</p>
        <p style="margin: 12px 0 0 0; color: #8a8098; font-size: 12px;"><a href="${site}" style="color: #8a8098;">${site}</a></p>
      </div>
    `

    const res = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.RESEND_API_KEY}`,
        'Content-Type':  'application/json',
      },
      body: JSON.stringify({
        from:    'GRAIL <hello@casadecopas.com>',
        to:      [email],
        subject: 'You\'re invited to GRAIL as a promoter',
        html,
      }),
    })

    if (!res.ok) {
      const body = await res.text()
      throw new Error(`Resend error ${res.status}: ${body}`)
    }

    return { statusCode: 200, body: JSON.stringify({ ok: true }) }
  } catch (err) {
    console.error('send-promoter-invite error:', err)
    return { statusCode: 500, body: JSON.stringify({ error: err.message }) }
  }
}

function escapeHtml(s) {
  return String(s || '').replace(/[&<>"']/g, ch => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[ch]))
}
